head.script:
scwin.isRenew = 0;
scwin.infoRowCnt = 0;
scwin.userClsCd = "";
scwin.clntNo = "";
scwin.clntNm = "";
scwin.vCurDate = "";

scwin.onpageload = async function() {
    scwin.userClsCd = $c.ses.getUserClsCd();
    scwin.clntNo = $c.ses.getClntNo();
    scwin.clntNm = $c.ses.getClntNm();
    if (scwin.userClsCd == null) scwin.userClsCd = "";
    if (scwin.clntNo == null) scwin.clntNo = "";
    if (scwin.clntNm == null) scwin.clntNm = "";
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");

    scwin.f_clearData();

    ed_clntNo.setFocus();

    if (scwin.userClsCd != "01") {
        ed_clntNo.setValue(scwin.clntNo);
        txt_clntNm.setValue(scwin.clntNm);
        $c.gus.cfDisableObjects([ed_clntNo, txt_clntNm]);
    } else {
        $c.gus.cfEnableObjects([ed_clntNo, txt_clntNm]);
    }

    $c.gus.cfDisableKeyData();
    $c.gus.cfDisableObjects([ica_ctrtDt, ica_ctrtStDt, ica_ctrtEndDt]);
    $c.gus.cfDisableBtn([btn_save]);
};

scwin.onUdcCompleted = function() {
    if (scwin.userClsCd != "01") {
        ed_clntNo.setValue(scwin.clntNo);
        txt_clntNm.setValue(scwin.clntNm);
        $c.gus.cfDisableObjects([ed_clntNo, txt_clntNm]);
    } else {
        $c.gus.cfEnableObjects([ed_clntNo, txt_clntNm]);
    }

    $c.gus.cfDisableKeyData();
    $c.gus.cfDisableObjects([ica_ctrtDt, ica_ctrtStDt, ica_ctrtEndDt]);
    $c.gus.cfDisableBtn([btn_save]);
};

scwin.f_createHeader = function() {
    dma_queryCondition.set("ctrtNo", "");
    dma_queryCondition.set("clntNo", "");

    dma_query.set("ctrtNo", "");
    dma_query.set("clntNo", "");

    ds_customerPurchaseInformation.removeAll();
    if (ds_customerPurchaseInformation.getRowCount() == 0) {
        ds_customerPurchaseInformation.insertRow(0);
    }

    ds_img.removeAll();
};

scwin.f_Retrieve = async function() {
    if (!(await $c.gus.cfValidate([tb_mainData]))) return;

    dma_queryCondition.set("clntNo", ed_clntNo.getValue());
    dma_queryCondition.set("ctrtNo", lc_ctrtNo.getValue());

    await $c.sbm.execute(sbm_retrieve);

    if (scwin.f_getRowCnt() == 0) {
        scwin.f_clearData();
    }

    $c.gus.cfDisableKeyData();
    $c.gus.cfDisableObjects([ica_ctrtDt, ica_ctrtStDt, ica_ctrtEndDt]);
    $c.gus.cfDisableBtn([btn_save]);
};

scwin.f_Renewal = async function() {
    let row = ds_customerPurchaseInformation.getRowPosition();
    if (row < 0 || ds_customerPurchaseInformation.getCellData(row, "ctrtNo") == "") {
        await $c.win.alert("먼저 조회를 하십시요");
        return;
    }

    if (dma_queryCondition.get("ctrtNo").trim() == "" || dma_queryCondition.get("clntNo").trim() == "") {
        dma_queryCondition.set("ctrtNo", ds_customerPurchaseInformation.getCellData(row, "ctrtNo"));
        dma_queryCondition.set("clntNo", ds_customerPurchaseInformation.getCellData(row, "clntNo"));
    }

    await $c.sbm.execute(sbm_renewal);

    ds_img.removeAll();

    $c.gus.cfEnableObjects([ica_ctrtDt, ica_ctrtStDt, ica_ctrtEndDt]);
    $c.gus.cfDisableBtn([btn_trigger2, btn_edit, btn_trigger1]);

    scwin.f_InitObjects();

    scwin.isRenew = 2;
};

scwin.f_Save = async function() {
    if (ds_customerPurchaseInformation.getUpdatedIndex().length == 0 && ds_img.getUpdatedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["계약관리"]);
        return;
    }

    if (!(await $c.gus.cfValidate([ed_clntNo2]))) return;

    let ctrtStDtVal = ds_customerPurchaseInformation.getCellData(ds_customerPurchaseInformation.getRowPosition(), "ctrtStDt");
    if (!$c.gus.cfValidateValue(ctrtStDtVal, "date=YYYYMMDD")) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_018, ["계약기간"]);
        ica_ctrtStDt.setFocus();
        return;
    }

    let ctrtEndDtVal = ds_customerPurchaseInformation.getCellData(ds_customerPurchaseInformation.getRowPosition(), "ctrtEndDt");
    if (!$c.gus.cfValidateValue(ctrtEndDtVal, "date=YYYYMMDD")) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_018, ["계약기간"]);
        ica_ctrtEndDt.setFocus();
        return;
    }

    if (!$c.gus.cfIsAfterDate(ctrtStDtVal, ctrtEndDtVal)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ica_ctrtStDt.setFocus();
        return;
    }

    await $c.sbm.execute(sbm_save);

    $c.gus.cfDisableKeyData();
    $c.gus.cfDisableObjects([ica_ctrtDt, ica_ctrtStDt, ica_ctrtEndDt]);
    $c.gus.cfDisableBtn([btn_save]);

    scwin.f_InitObjects();

    scwin.isRenew = 0;
};

scwin.fileSubmit = async function() {
    let chk = await $c.win.confirm(MSG_CM_CRM_001);
    if (chk) {
        // TODO: $c.gus.cfUploadFile 호출 (파일 업로드 UDC 연동)
    }
};

scwin.f_Create = async function() {
    scwin.f_InitObjects();
    scwin.f_clearData();

    $c.gus.cfEnableKeyData();
    $c.gus.cfEnableObjects([ica_ctrtDt, ica_ctrtStDt, ica_ctrtEndDt]);
    $c.gus.cfDisableBtn([btn_trigger2, btn_edit, btn_trigger1]);

    await $c.sbm.execute(sbm_retrieveCtrtNo);

    scwin.isRenew = 1;
};

scwin.f_Update = function() {
    $c.gus.cfEnableKeyData();

    $c.gus.cfDisableObjects([ed_clntNo2, txt_clntNm2]);
    $c.gus.cfEnableObjects([ica_ctrtDt, ica_ctrtStDt, ica_ctrtEndDt]);
    $c.gus.cfDisableBtn([btn_edit, btn_trigger2]);
};

scwin.f_InitObjects = function() {
    $c.gus.cfInitObjects(tb_subData);
    ds_ctrtList.removeAll();
    lc_ctrtNo.setValue("");
};

scwin.f_clearData = function() {
    ds_customerPurchaseInformation.removeAll();
    ds_img.removeAll();
    ds_vehicle.removeAll();

    scwin.f_createHeader();

    ica_ctrtDt.setValue(scwin.vCurDate);

    telNo.setLabel("");
    busiNo.setLabel("");
    mpNo.setLabel("");
    bizcond.setLabel("");
    addr.setLabel("");
    repstNm.setLabel("");
    catBusi.setLabel("");
    txt_clntNm2.setValue("");

    ed_clntNo2.setValue("");
    numOfVehicle.setLabel("0");

    $c.gus.cfDisableObjects([ed_ctrtNo2]);

    if (scwin.userClsCd != "01") {
        ed_clntNo.setValue(scwin.clntNo);
        txt_clntNm.setValue(scwin.clntNm);
    }
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:
            udc_clnt.ilCommonPopUp(scwin.callbackClnt1,
                pCode, pName, pClose, '5', null, '150,170',
                null, null, null, null, null, null, null,
                pAllSearch, "매입거래처,거래처코드,거래처명");
            break;
        case 2:
            udc_clntNo2.ilCommonPopUp(scwin.callbackClnt2,
                pCode, pName, pClose, '5', null, '150,170',
                null, null, null, null, null, null, null,
                pAllSearch, "매입거래처,거래처코드,거래처명");
            break;
        default:
            break;
    }
};

scwin.callbackClnt1 = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_clntNo, txt_clntNm);

    if (rtnList != null && ed_clntNo.getValue().trim() != "" && txt_clntNm.getValue().trim() != "") {
        dma_queryCondition.set("clntNo", ed_clntNo.getValue());
        await $c.sbm.execute(sbm_retrieveCtrtList);
    }
};

scwin.callbackClnt2 = async function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_clntNo2, txt_clntNm2);

    let temp_ctrtNo2 = ed_ctrtNo2.getValue();

    if (rtnList != null && ed_clntNo2.getValue().trim() != "" && txt_clntNm2.getValue().trim() != "") {
        dma_query.set("clntNo", ed_clntNo2.getValue());
        await $c.sbm.execute(sbm_getClntInfo);
        if (scwin.f_getRowCnt() == 0) {
            let row = ds_customerPurchaseInformation.getRowPosition();
            if (row >= 0) {
                ds_customerPurchaseInformation.setCellData(row, "ctrtNo", temp_ctrtNo2);
            }
        }
    } else {
        let row = ds_customerInformation.getRowPosition();
        if (row >= 0) {
            ds_customerInformation.setCellData(row, "ctrtNo", temp_ctrtNo2);
        }
    }
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    $c.gus.cfClearPairObj(pairObj);

    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.uploadComplete = function() {
    fileUploadGDS.sort("fileId", "asc");

    for (let i = 0; i < fileUploadGDS.getRowCount(); i++) {
        let newRow = ds_img.insertRow(ds_img.getRowCount());
        ds_img.setCellData(newRow, "ctrtNo", ed_ctrtNo2.getValue());

        ds_img.setCellData(newRow, "imgFileNm",
            ds_img.getCellData(newRow, "ctrtNo") + "_" + fileUploadGDS.getCellData(i, "filename"));
        ds_img.setCellData(newRow, "imgFilePathNm", fileUploadGDS.getCellData(i, "filepath"));
    }

    scwin.f_previewImg(ds_img.getRowCount() - 1);
};

scwin.f_previewImg = function(rowNum) {
    if (rowNum >= 0 && rowNum < ds_img.getRowCount()) {
        preView.setSrc($c.gus.cfGetFileURL("", ds_img.getCellData(rowNum, "imgFilePathNm")));
    }
};

scwin.f_ZoomIn = async function() {
    let row = ds_img.getRowPosition();
    if (row >= 0) {
        let strParam = $c.gus.cfGetFileURL("", ds_img.getCellData(row, "imgFilePathNm"));
        await $c.win.openPopup("/ui/common/popup/zoom.xml", {
            width: 840,
            height: 660,
            modal: true,
            data: { imgUrl: strParam }
        });
    }
};

scwin.f_setRowCnt = function(rowCnt) {
    scwin.infoRowCnt = rowCnt;
};

scwin.f_getRowCnt = function() {
    return scwin.infoRowCnt;
};

scwin.sbm_retrieve_submitdone = function(e) {
};

scwin.sbm_retrieve_submiterror = async function(e) {
    await $c.win.alert(e.errorMsg);
};

scwin.sbm_save_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
};

scwin.sbm_save_submiterror = async function(e) {
    await $c.win.alert(e.errorMsg);
};

scwin.sbm_retrieveCtrtList_submitdone = function(e) {
};

scwin.sbm_retrieveCtrtList_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_getClntInfo_submitdone = function(e) {
};

scwin.sbm_getClntInfo_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_renewal_submitdone = function(e) {
};

scwin.sbm_renewal_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_create_submitdone = function(e) {
};

scwin.sbm_create_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_retrieveCtrtNo_submitdone = function(e) {
    if (ds_ctrtNo.getRowCount() > 0) {
        ed_ctrtNo2.setValue(ds_ctrtNo.getCellData(ds_ctrtNo.getRowCount() - 1, "code"));
    }
};

scwin.sbm_retrieveCtrtNo_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.ds_customerPurchaseInformation_onloadcompleted = async function(e) {
    let rowCnt = ds_customerPurchaseInformation.getRowCount();
    if (rowCnt == 0) {
        scwin.f_clearData();
        scwin.f_setRowCnt(rowCnt);
        await $c.win.alert("조회된 데이터가 없습니다.");
    } else {
        scwin.f_setRowCnt(rowCnt);
        let row = ds_customerPurchaseInformation.getRowPosition();
        telNo.setLabel(ds_customerPurchaseInformation.getCellData(row, "telNo"));
        busiNo.setLabel(ds_customerPurchaseInformation.getCellData(row, "busiNo"));
        mpNo.setLabel(ds_customerPurchaseInformation.getCellData(row, "mpNo"));
        bizcond.setLabel(ds_customerPurchaseInformation.getCellData(row, "bizcond"));
        addr.setLabel(ds_customerPurchaseInformation.getCellData(row, "addr"));
        repstNm.setLabel(ds_customerPurchaseInformation.getCellData(row, "repstNm"));
        catBusi.setLabel(ds_customerPurchaseInformation.getCellData(row, "catBusi"));

        scwin.f_chkOpenCommonPopUp(ed_clntNo2, txt_clntNm2, 2);
    }
};

scwin.ds_customerInformation_onloadcompleted = async function(e) {
    let rowCnt = ds_customerInformation.getRowCount();
    if (rowCnt == 0) {
        scwin.f_setRowCnt(rowCnt);
        await $c.win.alert("해당 거래처의 데이터가 없습니다.");
    } else {
        scwin.f_setRowCnt(rowCnt);
        let row = ds_customerInformation.getRowPosition();
        telNo.setLabel(ds_customerInformation.getCellData(row, "telNo"));
        busiNo.setLabel(ds_customerInformation.getCellData(row, "busiNo"));
        mpNo.setLabel(ds_customerInformation.getCellData(row, "mpNo"));
        bizcond.setLabel(ds_customerInformation.getCellData(row, "bizcond"));
        addr.setLabel(ds_customerInformation.getCellData(row, "addr"));
        repstNm.setLabel(ds_customerInformation.getCellData(row, "repstNm"));
        catBusi.setLabel(ds_customerInformation.getCellData(row, "catBusi"));
        lc_coClsCd.setValue(ds_customerInformation.getCellData(row, "coClsCd"));
        lc_eqClssCd.setValue(ds_customerInformation.getCellData(row, "eqClssCd"));
    }
};

scwin.ds_vehicle_onloadcompleted = function(e) {
    numOfVehicle.setLabel(String(ds_vehicle.getRowCount()));
};

scwin.ed_clntNo_onblur = function(e) {
    scwin.f_chkOpenCommonPopUp(ed_clntNo, txt_clntNm, 1);
};

scwin.ed_clntNo2_onblur = function(e) {
    scwin.f_chkOpenCommonPopUp(ed_clntNo2, txt_clntNm2, 2);
};

scwin.ds_img_onrowpositionchange = function(e) {
    let row = ds_img.getRowPosition();
    if (row >= 0) {
        scwin.f_previewImg(row);
        preView.setStyle("display", "");
    } else {
        preView.setStyle("display", "none");
    }
};

scwin.ds_img_onloadcompleted = function(e) {
    let rowCnt = ds_img.getRowCount();
    if (rowCnt == 0) {
        preView.setStyle("display", "none");
    } else {
        preView.setStyle("display", "");
    }
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_InitObjects();
};

scwin.btn_trigger1_onclick = function(e) {
    scwin.f_Renewal();
};

scwin.btn_trigger2_onclick = function(e) {
    scwin.f_Create();
};

scwin.btn_edit_onclick = function(e) {
    scwin.f_Update();
};

scwin.btn_save_onclick = function(e) {
    scwin.f_Save();
};

scwin.txt_clntNm_onchange = function(e) {
    scwin.f_chkOpenCommonPopUp(txt_clntNm, ed_clntNo, 1, false);
};

scwin.txt_clntNm2_onchange = function(e) {
    scwin.f_chkOpenCommonPopUp(txt_clntNm2, ed_clntNo2, 2, false);
};

scwin.preView_onclick = function(e) {
    scwin.f_ZoomIn();
};
